import nodemailer from 'nodemailer';
import { Resend } from 'resend';

export function getMailTransporter() {
  const user = process.env.EMAIL_USER;
  const pass = process.env.EMAIL_APP_PASSWORD;
  if (!user || !pass) return null;
  return nodemailer.createTransport({
    service: 'gmail',
    auth: { user, pass },
  });
}

/**
 * Optional second Gmail (or Google Workspace) account used only for CRM / invoice outbound.
 * When set, customer replies go to this inbox instead of mixing with `EMAIL_USER` (form notifications).
 */
function getCrmSmtpTransporter() {
  const user = process.env.CRM_SMTP_USER?.trim();
  const pass = process.env.CRM_SMTP_PASSWORD?.trim();
  if (user && pass) {
    return nodemailer.createTransport({
      service: 'gmail',
      auth: { user, pass },
    });
  }
  return getMailTransporter();
}

/**
 * Address shown as From on CRM / invoice mail (and where customers’ replies go, unless Reply-To is set).
 * - With Resend: `RESEND_FROM` only.
 * - With Gmail: same account as quote forms (`EMAIL_USER`) by default, or optional `CRM_FROM_EMAIL` for a display name.
 */
export function getCrmFromAddress(): string | null {
  const resendKey = process.env.RESEND_API_KEY?.trim();
  if (resendKey) {
    return process.env.RESEND_FROM?.trim() || null;
  }

  const fromOverride = process.env.CRM_FROM_EMAIL?.trim();
  const crmUser = process.env.CRM_SMTP_USER?.trim();
  const crmPass = process.env.CRM_SMTP_PASSWORD?.trim();
  if (crmUser && crmPass) {
    return fromOverride || crmUser;
  }

  return fromOverride || process.env.EMAIL_USER?.trim() || null;
}

/** Reply-To header so replies reach a monitored inbox (optional; defaults to client behavior on From). */
export function getCrmReplyTo(): string | undefined {
  const raw = process.env.CRM_REPLY_TO_EMAIL?.trim();
  return raw || undefined;
}

function htmlToPlainFallback(html: string): string {
  return html
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

export async function sendCrmEmail(options: {
  to: string;
  subject: string;
  text: string;
  html?: string;
}): Promise<void> {
  const resendKey = process.env.RESEND_API_KEY?.trim();
  const from = getCrmFromAddress();
  const replyTo = getCrmReplyTo();
  const html = options.html ?? options.text.replace(/\n/g, '<br/>');

  if (resendKey) {
    if (!from) {
      throw new Error('Set RESEND_FROM (verified domain) for Resend outbound');
    }
    const resend = new Resend(resendKey);
    const { error } = await resend.emails.send({
      from,
      to: options.to,
      subject: options.subject,
      text: options.text,
      html,
      ...(replyTo ? { replyTo } : {}),
    });
    if (error) {
      throw new Error(error.message || 'Resend send failed');
    }
    return;
  }

  const transporter = getCrmSmtpTransporter();
  if (!transporter || !from) {
    throw new Error(
      'CRM email is not configured: set EMAIL_USER + EMAIL_APP_PASSWORD (same as quote forms), or Resend (RESEND_API_KEY + RESEND_FROM), or optional CRM_SMTP_USER + CRM_SMTP_PASSWORD'
    );
  }
  await transporter.sendMail({
    from,
    to: options.to,
    subject: options.subject,
    text: options.text,
    html,
    ...(replyTo ? { replyTo } : {}),
  });
}

export { htmlToPlainFallback };
